// parsedData should be an array of lessons from your JSON
const lessons = $json.parsedData;
const source = lessons;

return source.map(item => ({
  json: item,
}));

const chunkSize = 900;

function clean(str) {
  return str
    .replace(/\r?\n+/g, ' ')
    .replace(/\s+/g, ' ')
    .replace(/\[.*?\]\(.*?\)/g, '')
    .replace(/[#*_`>~=-]/g, '')
    .trim();
}

const inputItems = $input.all();
let out = [];

for (const item of inputItems) {
  const lesson = item.json;
  const text = clean(lesson.content_md || '');

  for (let i = 0; i < text.length; i += chunkSize) {
    out.push({
      json: {
        ...lesson,
        text_chunk: text.slice(i, i + chunkSize),
        chunk_index: Math.floor(i / chunkSize),
      },
    });
  }
}

return out;

// items = array of workflow items n8n gives this node automatically
// Each item has .json.lesson_text

return items.map(item => {
  let text = (item.json.lesson_text || '').toString();

  // Clean & shrink text
  text = text
    .replace(/\r?\n+/g, ' ')
    .replace(/\s+/g, ' ')
    .replace(/\[.*?\]\(.*?\)/g, '')
    .replace(/[#*_`>~=-]/g, '')
    .trim()
    .slice(0, 600);

  return {
    json: {
      ...item.json,
      safe_text: text,
    }
  };
});

const safeText = $node['Prepare Lesson Text'].json.safe_text || '';

// Simple fuzzy match function
function fuzzyMatch(text, reference) {
  if (!text || !reference) return false;
  const refWords = reference.toLowerCase().split(/\s+/);
  const textWords = text.toLowerCase().split(/\s+/);
  let matchCount = 0;
  for (const word of refWords) {
    if (textWords.includes(word)) matchCount++;
  }
  const matchRatio = matchCount / refWords.length;
  return matchRatio >= 0.7; // 70% word match threshold
}

// Get all incoming items
const allItems = $items();

// Metadata node fallback
const metaNode = $node['Set – Lesson Metadata'].json || {};

return allItems.flatMap((item) => {
  const json = item.json || {};
  const lessonText = json.parsedQuestions?.lesson_text || '';
  const qaPairs = Array.isArray(json.parsedQuestions?.qa_pairs)
    ? json.parsedQuestions.qa_pairs
    : [];

  const lessonMatches = fuzzyMatch(lessonText, safeText);

  return qaPairs.map((q, index) => ({
    json: {
      lesson_slug: metaNode.lesson_slug || '',
      lesson_title: metaNode.lesson_title || '',
      topic: metaNode.topic || '',
      level: typeof metaNode.level === 'number' ? metaNode.level : 0,

      question: q.question,
      answer: q.answer,
      difficulty: typeof q.difficulty === 'number' ? q.difficulty : 1,
      category: q.category || 'unspecified',
      question_type: q.question_type || 'short_answer',
      source: lessonMatches ? 'baseline' : 'llm_hallucinated',
      index,
    }
  }));
});

const allItems = $input.all();
const dataArray = allItems.map(item => item.json);
const jsonString = JSON.stringify(dataArray, null, 2);

return [{ json: { fileContent: jsonString } }];
